 declare(strict_types=1); namespace League\CommonMark\Extension\Footnote\Renderer; use League\CommonMark\ElementRendererInterface; use League\CommonMark\Extension\Footnote\Node\FootnoteBackref; use League\CommonMark\HtmlElement; use League\CommonMark\Inline\Element\AbstractInline; use League\CommonMark\Inline\Renderer\InlineRendererInterface; use League\CommonMark\Util\ConfigurationAwareInterface; use League\CommonMark\Util\ConfigurationInterface; final class FootnoteBackrefRenderer implements InlineRendererInterface, ConfigurationAwareInterface { private $config; public function render(AbstractInline $inline, ElementRendererInterface $htmlRenderer) { if (!($inline instanceof FootnoteBackref)) { throw new \InvalidArgumentException('Incompatible inline type: ' . \get_class($inline)); } $attrs = $inline->getData('attributes', []); $attrs['class'] = $attrs['class'] ?? $this->config->get('footnote/backref_class', 'footnote-backref'); $attrs['rev'] = 'footnote'; $attrs['href'] = \mb_strtolower($inline->getReference()->getDestination()); $attrs['role'] = 'doc-backlink'; return '&nbsp;' . new HtmlElement('a', $attrs, '&#8617;', true); } public function setConfiguration(ConfigurationInterface $configuration) { $this->config = $configuration; } } 